-- Add PROJECT_DELETED to the AuditAction enum so an empty, mistakenly-created
-- project can be deleted with a proper audit trail. A project with logged work
-- is still refused a delete (archive preserves the hours) — this only records
-- the removal of a project that had nothing behind it.
ALTER TABLE `audit_logs` MODIFY `action` ENUM('LOGIN', 'LOGIN_FAILED', 'LOGOUT', 'TOKEN_REFRESH', 'TOKEN_REUSE_DETECTED', 'PASSWORD_RESET_REQUESTED', 'PASSWORD_RESET_COMPLETED', 'PASSWORD_CHANGED', 'PASSWORD_RESET_BY_ADMIN', 'PROFILE_UPDATED', 'AVATAR_UPLOADED', 'USER_CREATED', 'USER_UPDATED', 'USER_DEACTIVATED', 'USER_REACTIVATED', 'USER_DELETED', 'ROLE_CHANGED', 'TEAM_CREATED', 'TEAM_UPDATED', 'TEAM_DELETED', 'TEAM_LEAD_ASSIGNED', 'TEAM_MEMBER_ASSIGNED', 'PROJECT_CREATED', 'PROJECT_UPDATED', 'PROJECT_DELETED', 'DEPARTMENT_CREATED', 'DEPARTMENT_UPDATED', 'DEPARTMENT_DELETED', 'TASK_CREATED', 'TASK_UPDATED', 'TASK_DELETED', 'TASK_EDITED_BY_LEAD', 'TASK_DAY_SUBMITTED', 'TASK_DAY_APPROVED', 'TASK_DAY_REJECTED', 'TASK_DAY_REOPENED', 'REPORT_EXPORTED', 'SETTING_UPDATED', 'RETENTION_CLEANUP') NOT NULL;
